import{Logger}from '../shared/logger.js';const SearchEnhancements={config:{maxRecentSearches: 10,debounceMs: 300,storageKey: 'sadec_recent_searches'},state:{recentSearches: [],currentQuery: '',isActive: false},init(){Logger.log('[SearchEnhancements] Initializing');this.loadRecentSearches();this.setupKeyboardShortcut();this.setupSearchListeners();},loadRecentSearches(){try{const stored=localStorage.getItem(this.config.storageKey);this.state.recentSearches=stored ? JSON.parse(stored): [];}catch(error){Logger.error('[SearchEnhancements] Failed to load recent searches',error);this.state.recentSearches=[];}},saveRecentSearches(){try{localStorage.setItem(this.config.storageKey,JSON.stringify(this.state.recentSearches));}catch(error){Logger.error('[SearchEnhancements] Failed to save recent searches',error);}},addRecentSearch(query){if(!query||query.trim().length===0)return;this.state.recentSearches=this.state.recentSearches.filter(s=>s!==query);this.state.recentSearches.unshift(query);if(this.state.recentSearches.length>this.config.maxRecentSearches){this.state.recentSearches.pop();}this.saveRecentSearches();this.onRecentSearchesChange();},clearRecentSearches(){this.state.recentSearches=[];this.saveRecentSearches();this.onRecentSearchesChange();},setupKeyboardShortcut(){document.addEventListener('keydown',(e)=>{if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();this.focusSearch();}});},setupSearchListeners(){document.addEventListener('command-palette:search',(e)=>{const{query}=e.detail;this.state.currentQuery=query;this.addRecentSearch(query);this.trackSearch(query);});},focusSearch(){const searchInput=document.querySelector('input[type="text"][placeholder*="Tìm"],input[type="search"]');if(searchInput){searchInput.focus();searchInput.select();}const commandPalette=document.querySelector('command-palette');if(commandPalette&&commandPalette.open){commandPalette.open();}},trackSearch(query){const event={type: 'search',query,timestamp: new Date().toISOString(),path: window.location.pathname};const analyticsKey='sadec_search_analytics';try{const analytics=JSON.parse(localStorage.getItem(analyticsKey)||'[]');analytics.push(event);localStorage.setItem(analyticsKey,JSON.stringify(analytics));}catch(error){Logger.error('[SearchEnhancements] Failed to track search',error);}Logger.debug('[SearchEnhancements] Tracked search:',query);},onRecentSearchesChange(){const event=new CustomEvent('search:recent-changed',{detail:{recentSearches: this.state.recentSearches}});document.dispatchEvent(event);},getRecentSearches(){return [...this.state.recentSearches];},fuzzySearch(query,items){const normalizedQuery=query.toLowerCase().trim();return items .map(item=>{const normalizedItem=item.toLowerCase();let score=0;let index=normalizedItem.indexOf(normalizedQuery);if(index===-1){const queryChars=normalizedQuery.split('');let matchCount=0;let lastIndex=-1;for(const char of queryChars){const charIndex=normalizedItem.indexOf(char,lastIndex+1);if(charIndex!==-1){matchCount++;lastIndex=charIndex;}}score=matchCount/query.length;}else{score=1-(index/normalizedItem.length);}return{item,score};}).filter(result=>result.score>0.3).sort((a,b)=>b.score-a.score);}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>SearchEnhancements.init());}else{SearchEnhancements.init();}export{SearchEnhancements};export default SearchEnhancements;